    cpc_list = []
    for code in sorted(cpc_codes):
        if code in cpc_title_map:
            cpc_list.append({
                'cpc_code': code,
                'title': cpc_title_map[code]
            })

    final_results.append({
        'assignee': assignee,
        'cpc_subclasses': cpc_list
    })

# Create summary
