for item in cpc_defs:
    cpc_title_map[item['symbol']] = item['titleFull']

# Group CPC codes by assignee
assignee_cpc = {}
for result in prev_result['sample_results']:
    assignee = result['assignee']
    if assignee not in assignee_cpc:
        assignee_cpc[assignee] = set()
    assignee_cpc[assignee].update(result['cpc_codes'])

# Build final answer structure
final_results = []
for assignee, cpc_codes in assignee_cpc.items():
    if assignee == 'UNIV CALIFORNIA':
        continue

    cpc_list = []
    for code in sorted(list(cpc_codes)):
        if code and code in cpc_title_map:
            cpc_list.append({
                'cpc_code': code,
                'title': cpc_title_map[code]
            })

    final_results.append({
        'assignee': assignee,
        'cpc_subclasses': cpc_list
    })

# Create plain text report
report_lines = []
for item in final_results:
    report_lines.append('')
    report_lines.append('ASSIGNEE: ' + item['assignee'])
    report_lines.append('-' * 60)
    for cpc_item in item['cpc_subclasses']:
        report_lines.append('  CPC Code: ' + cpc_item['cpc_code'])
        report_lines.append('  Title: ' + cpc_item['title'])
        report_lines.append('')

report_text = "\n".join(report_lines)

# Print result in required format
print('__RESULT__:')
print(json.dumps({
    'report': report_text,
    'summary': {
        'total_assignees': len(final_results),
        'assignees': [item['assignee'] for item in final_results]
    }
}, indent=2))
