{"code": "import json

# Load data from storage
prev_results = locals()['var_functions.execute_python:44']
cpc_definitions = locals()['var_functions.query_db:48']

# Create CPC title lookup
cpc_title_map = {}
for item in cpc_definitions:
    cpc_title_map[item['symbol']] = item['titleFull']

# Group data by assignee
assignee_cpc = {}
for patent in prev_results['sample_results']:
    assignee = patent['assignee']
    if assignee not in assignee_cpc:
        assignee_cpc[assignee] = set()
    for code in patent['cpc_codes']:
        if code:
            assignee_cpc[assignee].add(code)

# Build final results
results = []
for assignee, cpc_codes in assignee_cpc.items():
    if assignee == 'UNIV CALIFORNIA':
        continue
    cpc_list = []
    for code in sorted(list(cpc_codes)):
        if code in cpc_title_map:
            cpc_list.append({'cpc_code': code, 'title': cpc_title_map[code]})
    if cpc_list:
        results.append({'assignee': assignee, 'cpc_subclasses': cpc_list})

# Create formatted output
output = []
for r in results:
    output.append('')
    output.append('ASSIGNEE: ' + r['assignee'])
    output.append('=' * 70)
    for c in r['cpc_subclasses']:
        output.append('  CPC Code: ' + c['cpc_code'])
        output.append('  Title: ' + c['title'])
        output.append('')

report_text = '\n'.join(output)

summary = {
    'total_assignees': len(results),
    'assignee_names': [r['assignee'] for r in results]
}

print('__RESULT__:')
print(json.dumps({
    'report': report_text,
    'summary': summary
}))"}

