{"code": "import json
import re

# Get previous results
prev_results = locals()['var_functions.execute_python:44']
cpc_definitions = locals()['var_functions.query_db:48']

# Build CPC title map
cpc_title_map = {}
for item in cpc_definitions:
    cpc_title_map[item['symbol']] = item['titleFull']

# Process citing patents data
assignee_cpc_map = {}

for patent in prev_results['sample_results']:
    assignee = patent['assignee']
    if assignee == 'UNIV CALIFORNIA':
        continue

    if assignee not in assignee_cpc_map:
        assignee_cpc_map[assignee] = set()

    # Add CPC codes (filter out empty/invalid)
    for cpc_code in patent['cpc_codes']:
        if cpc_code and len(cpc_code.strip()) > 0:
            assignee_cpc_map[assignee].add(cpc_code)

# Build final structured results
results = []
for assignee, cpc_codes in assignee_cpc_map.items():
    cpc_list = []
    for code in sorted(list(cpc_codes)):
        if code in cpc_title_map:
            cpc_list.append({
                'cpc_code': code,
                'title': cpc_title_map[code]
            })

    if cpc_list:  # Only include if we found valid CPC titles
        results.append({
            'assignee': assignee,
            'cpc_subclasses': cpc_list
        })

# Create formatted report
report_lines = []
for result in results:
    report_lines.append('')
    report_lines.append('ASSIGNEE: ' + result['assignee'])
    report_lines.append('=' * 70)
    for cpc in result['cpc_subclasses']:
        report_lines.append('  CPC Code: ' + cpc['cpc_code'])
        report_lines.append('  Title: ' + cpc['title'])
        report_lines.append('')

final_report = '\n'.join(report_lines)

# Summary information
summary = {
    'total_assignees': len(results),
    'assignee_names': [r['assignee'] for r in results],
    'total_cpc_codes': sum(len(r['cpc_subclasses']) for r in results)
}

print('__RESULT__:')
print(json.dumps({
    'report': final_report,
    'summary': summary
}, indent=2))"}

