# Process citing patents data
assignee_cpc_map = {}

for patent in prev_results['sample_results']:
    assignee = patent['assignee']
    if assignee == 'UNIV CALIFORNIA':
        continue

    if assignee not in assignee_cpc_map:
        assignee_cpc_map[assignee] = set()

    # Add CPC codes (filter out empty/invalid)
    for cpc_code in patent['cpc_codes']:
        if cpc_code and len(cpc_code.strip()) > 0:
            assignee_cpc_map[assignee].add(cpc_code)

# Build final structured results
results = []
for assignee, cpc_codes in assignee_cpc_map.items():
    cpc_list = []
    for code in sorted(list(cpc_codes)):
        if code in cpc_title_map:
            cpc_list.append({
                'cpc_code': code,
                'title': cpc_title_map[code]
            })

    if cpc_list:  # Only include if we found valid CPC titles
