{"code": "import json
import re

# Load all patent data to find citing patterns
all_file = locals()['var_functions.query_db:28']
with open(all_file, 'r') as f:
    all_patents = json.load(f)

print('Total patents to analyze:', len(all_patents))

# First, let's identify ALL UC publication numbers
uc_pubs = set()

for patent in all_patents:
    info = patent['Patents_info']
    if 'UNIV CALIFORNIA' in info:
        match = re.search(r'(?:pub\. number|publication number|pub\. no\.)\s+([A-Z0-9-]+)', 
                          info, re.IGNORECASE)
        if match:
            uc_pubs.add(match.group(1))

print('Total UC publication numbers found:', len(uc_pubs))
print('Sample UC pubs:', list(uc_pubs)[:10])

# Now find ALL patents that cite these UC patents (excluding UC itself)
citing_patents = []

for i, patent in enumerate(all_patents):
    if i % 5000 == 0:
        print(f'Processing {i}/{len(all_patents)}...')

    info = patent['Patents_info']
    if 'UNIV CALIFORNIA' in info:
        continue

    citations_str = patent.get('citation', '[]')
    if citations_str and citations_str != '[]':
        try:
            citations = json.loads(citations_str)
            for citation in citations:
                cited_pub = citation.get('publication_number')
                if cited_pub and cited_pub in uc_pubs:
                    # Extract assignee more carefully
                    assignee = 'Unknown'

                    # Try multiple patterns
                    patterns = [
                        r'^\s*([A-Z][A-Z0-9\s\&\-\.]{3,}?(?:INC|LLC|CO|LTD|CORP|GMBH|AG|UNIVERSITY|INSTITUTE|RESEARCH))\b',
                        r'(?:is assigned to|owned by|held by)\s+([A-Z][A-Z0-9\s\&\-\.]{3,}?(?:INC|LLC|CO|LTD|CORP|GMBH|AG|UNIVERSITY|INSTITUTE|RESEARCH))\b',
                        r'^(\S+\s+\S+\s+(?:INC|LLC|CO|LTD|CORP|GMBH|AG|UNIVERSITY|INSTITUTE|RESEARCH))\b'
                    ]

                    for pattern in patterns:
                        match = re.search(pattern, info, re.IGNORECASE)
                        if match:
                            assignee = match.group(1).strip()
                            break

                    # If we got "Unknown", try a simpler approach
                    if assignee == 'Unknown':
                        words = info.split()
                        if len(words) >= 2:
                            # Take first 2-4 capitalized words
                            name_parts = []
                            for word in words[:4]:
                                if re.match(r'^[A-Z]', word) or word.isupper():
                                    name_parts.append(word.rstrip(',.;:'))
                                else:
                                    break
                            if name_parts and len(name_parts) >= 2:
                                assignee = ' '.join(name_parts)

                    citing_patents.append({
                        'assignee': assignee,
                        'cited_uc_patent': cited_pub,
                        'cpc_data': patent.get('cpc', '[]'),
                        'patent_info': info[:150]
                    })
        except Exception as e:
            continue

print('\nTotal citing patents found:', len(citing_patents))
print('Sample citing patents:')
for i, p in enumerate(citing_patents[:5]):
    print(f"  {i+1}. {p['assignee']} cites {p['cited_uc_patent']}")
    print(f"     Info: {p['patent_info']}...")

# Count assignees
from collections import Counter
assignee_counts = Counter([p['assignee'] for p in citing_patents])
print(f'\nUnique assignees: {len(assignee_counts)}')
print('Top assignees:')
for assignee, count in assignee_counts.most_common(10):
    print(f'  {assignee}: {count}')

result = {
    'citing_patents': citing_patents,
    'assignee_counts': dict(assignee_counts),
    'total_citing': len(citing_patents),
    'uc_publications': len(uc_pubs)
}

print('__RESULT__:')
print(json.dumps(result))"}

