# Find patents citing UC patents
citing = []
for patent in all_patents:
    info = patent['Patents_info']
    if 'UNIV CALIFORNIA' in info:
        continue

    citations_str = patent.get('citation', '[]')
    if citations_str and citations_str != '[]':
        try:
            citations = json.loads(citations_str)
            for citation in citations:
                cited_pub = citation.get('publication_number')
                if cited_pub and cited_pub in uc_pubs:
                    # Extract assignee - simple pattern
                    assignee = 'Unknown'
                    match = re.search(r'^([A-Z][A-Z\s]{3,})(?:\s+INC|\s+LLC|\s+CORP|\s+CO|\s+LTD|\\s+GMBH)?\\b', info)
                    if match:
                        assignee = match.group(1).strip()

                    citing.append({
                        'assignee': assignee,
                        'cited': cited_pub,
                        'cpc': patent.get('cpc', '[]'),
                        'info': info[:100]
                    })
        except:
            pass

print('Citing patents found:', len(citing))

from collections import Counter
assignee_counts = Counter([p['assignee'] for p in citing])
print('Unique assignees:', len(assignee_counts))

result = {
    'citing_patents': citing,
    'assignee_counts': dict(assignee_counts),
    'total': len(citing)
}

print('__RESULT__:')
print(json.dumps(result))"}

