{"code": "import json
import re

# Get UC patents file path
uc_file_path = locals()['var_functions.query_db:20']

# Read all patents assigned to UNIV CALIFORNIA
with open(uc_file_path, 'r') as f:
    uc_patents = json.load(f)

# Build a mapping of publication numbers to UC patents for quick lookup
uc_pub_numbers = set()
for patent in uc_patents:
    # Extract publication number from Patents_info field
    info = patent['Patents_info']
    # Look for patterns like "pub. number US-2022074631-A1" or "publication number US-11081687-B2"
    match = re.search(r'(?:pub\. number|publication number|pub\. no\.)\s+([A-Z0-9-]+)', info, re.IGNORECASE)
    if match:
        uc_pub_numbers.add(match.group(1))

print('UC publication numbers found:', len(uc_pub_numbers))
print('Sample UC pub numbers:', list(uc_pub_numbers)[:10])

# Extract all cited publication numbers and map back to UC patents
citation_map = {}  # cited_pub_num -> list of uc_patent_info
for patent in uc_patents:
    citations_str = patent.get('citation', '[]')
    if citations_str and citations_str != '[]':
        try:
            citations = json.loads(citations_str)
            for citation in citations:
                cited_pub = citation.get('publication_number')
                if cited_pub:
                    if cited_pub not in citation_map:
                        citation_map[cited_pub] = []
                    citation_map[cited_pub].append(patent['Patents_info'])
        except:
            continue

print('Total unique cited publications:', len(citation_map))

print('__RESULT__:')
print(json.dumps({
    'uc_pub_numbers_count': len(uc_pub_numbers),
    'citation_map_size': len(citation_map),
    'sample_cited': list(citation_map.keys())[:5]
}))"}

{"code": "import json
import re

# Read data from files
uc_file = locals()['var_functions.query_db:20']
all_file = locals()['var_functions.query_db:28']

with open(uc_file, 'r') as f:
    uc_patents = json.load(f)

with open(all_file, 'r') as f:
    all_patents = json.load(f)

# Build UC publication numbers set
uc_pub_numbers = set()
for patent in uc_patents:
    info = patent['Patents_info']
    match = re.search(r'(?:pub\. number|publication number|pub\. no\.)\s+([A-Z0-9-]+)', 
                      info, re.IGNORECASE)
    if match:
        uc_pub_numbers.add(match.group(1))

print('UC patents count:', len(uc_patents))
print('UC pub numbers found:', len(uc_pub_numbers))

# Find citing patents
results = []
for patent in all_patents:
    info = patent['Patents_info']
    if 'UNIV CALIFORNIA' in info:
        continue

    citations_str = patent.get('citation', '[]')
    if citations_str and citations_str != '[]':
        try:
            citations = json.loads(citations_str)
            for citation in citations:
                cited_pub = citation.get('publication_number')
                if cited_pub and cited_pub in uc_pub_numbers:
                    # Get CPC codes
                    cpc_str = patent.get('cpc', '[]')
                    if cpc_str and cpc_str != '[]':
                        try:
                            cpc_list = json.loads(cpc_str)
                            cpc_codes = [item.get('code') for item in cpc_list if item.get('code')]
                        except:
                            cpc_codes = []
                    else:
                        cpc_codes = []

                    # Get assignee
                    assignee = 'Unknown'
                    words = info.split()
                    if words:
                        name_parts = []
                        for word in words[:6]:
                            if re.match(r'^[A-Z0-9\-]{2,}$', word):
                                name_parts.append(word)
                            else:
                                break
                        if name_parts:
                            name = ' '.join(name_parts)
                            name = re.split(r'\s+(?:and|holds|is|has|owns|assigned)\s+', name, 1)[0]
                            assignee = name

                    if assignee != 'UNIV CALIFORNIA':
                        results.append({
                            'assignee': assignee,
                            'cpc_codes': cpc_codes
                        })
        except:
            pass

print('Total citing patents found (excluding UC):', len(results))

# Count unique assignees
assignees = [r['assignee'] for r in results]
from collections import Counter
assignee_counts = Counter(assignees)
print('Unique assignees:', len(assignee_counts))

# Prepare CPC codes for lookup
all_cpc_codes = set()
for r in results:
    all_cpc_codes.update(r['cpc_codes'])

print('Unique CPC codes to look up:', len(all_cpc_codes))

output = {
    'total_results': len(results),
    'assignee_counts': dict(assignee_counts),
    'sample_results': results[:10],
    'cpc_codes_list': list(all_cpc_codes)[:50]  # First 50 for now
}

print('__RESULT__:')
print(json.dumps(output))"}

