                    assignee = 'Unknown'
                    words = info.split()
                    if words:
                        name_parts = []
                        for word in words[:6]:
                            if re.match(r'^[A-Z0-9\-]{2,}$', word):
                                name_parts.append(word)
                            else:
                                break
                        if name_parts:
                            name = ' '.join(name_parts)
                            name = re.split(r'\s+(?:and|holds|is|has|owns|assigned)\s+', name, 1)[0]
                            assignee = name

