# Load the comprehensive citing patents analysis
citing_file = locals()['var_functions.execute_python:76']
with open(citing_file, 'r') as f:
    citing_data = json.load(f)

# Load CPC definitions
cpc_defs = locals()['var_functions.query_db:48']

# Build CPC title lookup
cpc_titles = {}
for item in cpc_defs:
    cpc_titles[item['symbol']] = item['titleFull']

print('Total citing patents found:', citing_data['total'])
print('Unique assignees:', len(citing_data['assignee_counts']))

# Group CPC codes by assignee
assignee_cpc_map = {}

for patent in citing_data['citing_patents']:
    assignee = patent['assignee']

    # Skip UNIV CALIFORNIA if it appears
    if 'UNIV CALIFORNIA' in assignee.upper():
        continue

    if assignee not in assignee_cpc_map:
        assignee_cpc_map[assignee] = set()

    # Parse CPC codes
    cpc_str = patent['cpc']
    if cpc_str and cpc_str != '[]':
        try:
            cpc_list = json.loads(cpc_str)
            for cpc_item in cpc_list:
                code = cpc_item.get('code')
                if code and code in cpc_titles:
                    assignee_cpc_map[assignee].add(code)
        except:
            continue

# Build final answer
final_answer = []
for assignee in sorted(assignee_cpc_map.keys()):
    final_answer.append('')
    final_answer.append('CITING ASSIGNEE: ' + assignee)
    final_answer.append('=' * 70)

    for cpc_code in sorted(assignee_cpc_map[assignee]):
        final_answer.append('  CPC Subclass: ' + cpc_code)
        final_answer.append('  Full Title: ' + cpc_titles[cpc_code])
        final_answer.append('')

# Also create a structured version
structured_results = []
for assignee, cpc_codes in assignee_cpc_map.items():
    if assignee == 'UNIV CALIFORNIA':
        continue
    cpc_list = [{'code': code, 'title': cpc_titles[code]} for code in sorted(cpc_codes)]
    structured_results.append({
        'assignee': assignee,
        'cpc_subclasses': cpc_list
    })

print('\nSUMMARY:')
print(f'Found {len(structured_results)} assignees (excluding UNIV CALIFORNIA)')
for item in structured_results:
    print(f"  - {item['assignee']}: {len(item['cpc_subclasses'])} CPC subclasses")

final_text = '\n'.join(final_answer)
print('\n' + '='*70)
print('DETAILED RESULTS:')
print('='*70)
print(final_text)

output = {
    'summary': {
        'total_citing_assignees': len(structured_results),
        'assignees': [item['assignee'] for item in structured_results]
    },
    'detailed_results': structured_results,
    'formatted_report': final_text
}

print('__RESULT__:')
